import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress, Chip, Grid } from '@mui/material';
import response from './response.json';

interface Milestone {
  milestone: string;
  completed: boolean;
}

interface Goal {
  name: string;
  progress: number;
  milestones: Milestone[];
  deadline: string;
}

interface GoalTrackerData {
  activeGoals: Goal[];
}

export default function Widget() {
  const goalData = response.data as GoalTrackerData;
  const { activeGoals } = goalData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
            Goal Tracker
          </Typography>

          {activeGoals.slice(0, 3).map((goal) => (
            <Box key={goal.name} sx={{ mb: 2 }}>
              <Typography variant="body1" fontWeight={500} sx={{ color: '#1976D2' }}>
                {goal.name}
              </Typography>

              <Typography variant="caption" color="text.secondary">
                Deadline: {new Date(goal.deadline).toLocaleDateString()}
              </Typography>

              <Box sx={{ my: 1 }}>
                <LinearProgress
                  variant="determinate"
                  value={goal.progress}
                  sx={{
                    height: 8,
                    borderRadius: 4,
                    bgcolor: '#E0E0E0',
                    '& .MuiLinearProgress-bar': {
                      bgcolor: '#4CAF50',
                      borderRadius: 4,
                    },
                  }}
                />
                <Typography variant="caption" sx={{ color: '#4CAF50', mt: 0.5 }}>
                  {goal.progress}% completed
                </Typography>
              </Box>

              <Grid container spacing={1}>
                {goal.milestones.map((milestone, index) => (
                  <Grid item xs={6} key={index}>
                    <Chip
                      label={milestone.milestone}
                      variant={milestone.completed ? 'filled' : 'outlined'}
                      sx={{
                        fontSize: 11,
                        width: '100%',
                        bgcolor: milestone.completed ? '#C8E6C9' : 'transparent',
                      }}
                    />
                  </Grid>
                ))}
              </Grid>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
